252	```ts
253	export type PluginErrorCode =
254	  | 'no-service'
255	  | 'duplicate-service'
256	  | 'timeout'
257	  | 'invalid-payload'
258	  | 'invalid-manifest'
259	  | 'cycle'
260	  | 'missing-service'
261	  | 'init-failed'
262	  | 'subscriber-failed'
263	  | 'unknown';
264	
265	export interface PluginErrorOptions {
266	  code: PluginErrorCode;
267	  plugin: string;
268	  message: string;
269	  cause?: unknown;
270	}
271	
272	export class PluginError extends Error {
273	  readonly code: PluginErrorCode;
274	  readonly plugin: string;
275	
276	  constructor(opts: PluginErrorOptions) {
277	    super(opts.message, opts.cause !== undefined ? { cause: opts.cause } : undefined);
278	    this.name = 'PluginError';
279	    this.code = opts.code;
280	    this.plugin = opts.plugin;
281	  }
282	
283	  toJSON(): Record<string, unknown> {
284	    return {
285	      name: this.name,
286	      code: this.code,
287	      plugin: this.plugin,
288	      message: this.message,
289	    };
290	  }
291	}
292	
293	export interface Rejection {
294	  readonly rejected: true;
295	  readonly reason: string;
296	  readonly source?: string;
297	}
298	
299	export function reject(opts: { reason: string; source?: string }): Rejection {
300	  const r: Rejection = opts.source !== undefined
301	    ? { rejected: true, reason: opts.reason, source: opts.source }
302	    : { rejected: true, reason: opts.reason };
303	  return r;
304	}
305	
306	export function isRejection(value: unknown): value is Rejection {
307	  return (
308	    typeof value === 'object' &&
309	    value !== null &&
310	    (value as { rejected?: unknown }).rejected === true &&
311	    typeof (value as { reason?: unknown }).reason === 'string'
312	  );
313	}
314	```
