440	**Step 3: Implement `packages/core/src/context.ts`**
441	
442	```ts
443	import { randomBytes } from 'node:crypto';
444	
445	export function makeReqId(): string {
446	  return `req-${randomBytes(6).toString('hex')}`;
447	}
448	
449	export type LogLevel = 'debug' | 'info' | 'warn' | 'error';
450	
451	export interface Logger {
452	  debug(msg: string, bindings?: Record<string, unknown>): void;
453	  info(msg: string, bindings?: Record<string, unknown>): void;
454	  warn(msg: string, bindings?: Record<string, unknown>): void;
455	  error(msg: string, bindings?: Record<string, unknown>): void;
456	  child(bindings: Record<string, unknown>): Logger;
457	}
458	
459	export interface CreateLoggerOptions {
460	  reqId: string;
461	  writer?: (line: string) => void;
462	  bindings?: Record<string, unknown>;
463	}
464	
465	export function createLogger(opts: CreateLoggerOptions): Logger {
466	  const writer = opts.writer ?? ((line: string) => process.stdout.write(line + '\n'));
467	  const baseBindings: Record<string, unknown> = {
468	    reqId: opts.reqId,
469	    ...(opts.bindings ?? {}),
470	  };
471	
472	  const emit = (level: LogLevel, msg: string, extra?: Record<string, unknown>): void => {
473	    const entry: Record<string, unknown> = {
474	      level,
475	      ts: new Date().toISOString(),
476	      ...baseBindings,
477	      msg,
478	    };
479	    if (extra) {
480	      for (const [k, v] of Object.entries(extra)) {
481	        entry[k] = v instanceof Error ? serializeError(v) : v;
482	      }
483	    }
484	    writer(JSON.stringify(entry));
485	  };
486	
487	  return {
488	    debug: (msg, bindings) => emit('debug', msg, bindings),
489	    info: (msg, bindings) => emit('info', msg, bindings),
490	    warn: (msg, bindings) => emit('warn', msg, bindings),
491	    error: (msg, bindings) => emit('error', msg, bindings),
492	    child: (extra) =>
493	      createLogger({
494	        reqId: opts.reqId,
495	        ...(opts.writer !== undefined ? { writer: opts.writer } : {}),
496	        bindings: { ...baseBindings, ...extra },
497	      }),
498	  };
499	}
500	
501	function serializeError(err: Error): Record<string, unknown> {
502	  const out: Record<string, unknown> = {
503	    name: err.name,
504	    message: err.message,
505	  };
506	  if (err.stack !== undefined) out.stack = err.stack;
507	  return out;
508	}
509	
510	export interface ChatContext {
511	  readonly reqId: string;
512	  readonly sessionId: string;
513	  readonly agentId: string;
514	  readonly userId: string;
515	  readonly logger: Logger;
516	  readonly state: Map<string, unknown>;
517	}
518	
519	export interface MakeChatContextOptions {
520	  reqId?: string;
521	  sessionId: string;
522	  agentId: string;
523	  userId: string;
524	  logger?: Logger;
525	}
526	
527	export function makeChatContext(opts: MakeChatContextOptions): ChatContext {
528	  const reqId = opts.reqId ?? makeReqId();
529	  const logger = opts.logger ?? createLogger({ reqId });
530	  return {
531	    reqId,
532	    sessionId: opts.sessionId,
533	    agentId: opts.agentId,
534	    userId: opts.userId,
