725	
726	```ts
727	import type { ChatContext } from './context.js';
728	import { PluginError } from './errors.js';
729	
730	export type ServiceHandler<I = unknown, O = unknown> = (
731	  ctx: ChatContext,
732	  input: I,
733	) => Promise<O>;
734	
735	interface RegisteredService {
736	  plugin: string;
737	  handler: ServiceHandler;
738	}
739	
740	export class HookBus {
741	  private services = new Map<string, RegisteredService>();
742	
743	  registerService<I, O>(hookName: string, plugin: string, handler: ServiceHandler<I, O>): void {
744	    const existing = this.services.get(hookName);
745	    if (existing !== undefined) {
746	      throw new PluginError({
747	        code: 'duplicate-service',
748	        plugin,
749	        message: `service hook '${hookName}' already registered by plugin '${existing.plugin}'`,
750	      });
751	    }
752	    this.services.set(hookName, { plugin, handler: handler as ServiceHandler });
753	  }
754	
755	  hasService(hookName: string): boolean {
756	    return this.services.has(hookName);
757	  }
758	
759	  async call<I, O>(hookName: string, ctx: ChatContext, input: I): Promise<O> {
760	    const registered = this.services.get(hookName);
761	    if (registered === undefined) {
762	      throw new PluginError({
763	        code: 'no-service',
764	        plugin: 'core',
765	        message: `no plugin registered for service hook '${hookName}'`,
766	      });
767	    }
768	    try {
769	      return (await registered.handler(ctx, input)) as O;
770	    } catch (err) {
771	      if (err instanceof PluginError) throw err;
772	      throw new PluginError({
773	        code: 'unknown',
774	        plugin: registered.plugin,
775	        message: `service hook '${hookName}' threw: ${(err as Error).message ?? String(err)}`,
776	        cause: err,
777	      });
778	    }
779	  }
780	}
781	```
