926	  async fire<P>(hookName: string, ctx: ChatContext, payload: P): Promise<FireResult<P>> {
927	    const list = this.subscribers.get(hookName) ?? [];
928	    let current: P = payload;
929	    for (const sub of list) {
930	      let result: P | undefined | import('./errors.js').Rejection;
931	      try {
932	        result = await sub.handler(ctx, current);
933	      } catch (err) {
