1155	      const response = await bus.call<LlmRequest, LlmResponse>('llm:call', ctx, pre.payload);
1156	
1157	      const post = await bus.fire<LlmResponse>('llm:post-call', ctx, response);
1158	      if (post.rejected) {
1159	        return await terminate(bus, ctx, `llm:post-call:${post.reason}`);
1160	      }
1161	
1162	      messages.push(post.payload.assistantMessage);
1163	      if (post.payload.toolCalls.length === 0) break;
1164	
1165	      for (const toolCall of post.payload.toolCalls) {
1166	        const pre = await bus.fire<ToolCall>('tool:pre-call', ctx, toolCall);
1167	        if (pre.rejected) {
1168	          messages.push({
1169	            role: 'user',
1170	            content: `tool '${toolCall.name}' rejected: ${pre.reason}`,
1171	          });
1172	          continue;
1173	        }
1174	        let output: unknown;
1175	        try {
1176	          output = await bus.call('tool:execute', ctx, pre.payload);
1177	        } catch (err) {
1178	          if (err instanceof PluginError && err.code === 'no-service') {
1179	            return await terminate(bus, ctx, `no-service:tool:execute`);
1180	          }
1181	          throw err;
1182	        }
1183	        const postTool = await bus.fire('tool:post-call', ctx, { toolCall, output });
1184	        const finalOutput = postTool.rejected ? output : (postTool.payload as { output: unknown }).output;
1185	        messages.push({
1186	          role: 'user',
1187	          content: `[tool ${toolCall.name}] ${JSON.stringify(finalOutput)}`,
1188	        });
1189	      }
