1203	async function terminate(bus: HookBus, ctx: ChatContext, reason: string): Promise<ChatOutcome> {
1204	  const outcome: ChatOutcome = { kind: 'terminated', reason };
1205	  await bus.fire('chat:end', ctx, { outcome });
1206	  return outcome;
1207	}
1208	
1209	function classify(err: unknown): string {
1210	  if (err instanceof PluginError) {
1211	    if (err.code === 'no-service') return `no-service:${extractServiceName(err.message)}`;
1212	    return `plugin-error:${err.code}`;
1213	  }
1214	  return 'unknown';
1215	}
1216	
1217	function extractServiceName(message: string): string {
1218	  const match = message.match(/'([^']+)'/);
1219	  return match ? match[1]! : 'unknown';
