1392	import type { HookBus } from './hook-bus.js';
1393	import { PluginError } from './errors.js';
1394	import { PluginManifestSchema, type Plugin } from './plugin.js';
1395	
1396	export interface BootstrapOptions {
1397	  bus: HookBus;
1398	  plugins: Plugin[];
1399	  config: Record<string, unknown>;
1400	}
1401	
1402	export async function bootstrap(opts: BootstrapOptions): Promise<void> {
1403	  const { bus, plugins, config } = opts;
1404	
1405	  for (const p of plugins) {
1406	    const parsed = PluginManifestSchema.safeParse(p.manifest);
1407	    if (!parsed.success) {
1408	      throw new PluginError({
1409	        code: 'invalid-manifest',
1410	        plugin: p.manifest?.name ?? 'unknown',
1411	        message: `invalid plugin manifest: ${parsed.error.message}`,
1412	        cause: parsed.error,
1413	      });
1414	    }
1415	  }
1416	
1417	  detectCycles(plugins);
1418	
1419	  for (const p of plugins) {
1420	    try {
1421	      await p.init({ bus, config: (config as Record<string, unknown>)[p.manifest.name] });
1422	    } catch (err) {
1423	      if (err instanceof PluginError) throw err;
1424	      throw new PluginError({
1425	        code: 'init-failed',
1426	        plugin: p.manifest.name,
1427	        message: `plugin '${p.manifest.name}' init failed: ${(err as Error).message ?? String(err)}`,
1428	        cause: err,
1429	      });
1430	    }
1431	  }
1432	
1433	  verifyCalls(plugins, bus);
1434	}
1435	
1436	function detectCycles(plugins: Plugin[]): void {
1437	  const producers = new Map<string, string>();
1438	  for (const p of plugins) {
1439	    for (const r of p.manifest.registers) {
1440	      const existing = producers.get(r);
1441	      if (existing !== undefined && existing !== p.manifest.name) {
1442	        throw new PluginError({
1443	          code: 'duplicate-service',
1444	          plugin: p.manifest.name,
1445	          message: `service hook '${r}' registered by both '${existing}' and '${p.manifest.name}'`,
1446	        });
1447	      }
1448	      producers.set(r, p.manifest.name);
1449	    }
1450	  }
1451	
1452	  const graph = new Map<string, string[]>();
1453	  for (const p of plugins) {
1454	    const out: string[] = [];
1455	    for (const c of p.manifest.calls) {
1456	      const prod = producers.get(c);
1457	      if (prod !== undefined && prod !== p.manifest.name) out.push(prod);
1458	    }
1459	    graph.set(p.manifest.name, out);
1460	  }
1461	
1462	  const visiting = new Set<string>();
1463	  const done = new Set<string>();
1464	
1465	  const visit = (node: string, stack: string[]): void => {
1466	    if (done.has(node)) return;
1467	    if (visiting.has(node)) {
1468	      const cycleStart = stack.indexOf(node);
1469	      const cycle = stack.slice(cycleStart).concat(node).join(' → ');
1470	      throw new PluginError({
1471	        code: 'cycle',
1472	        plugin: node,
1473	        message: `plugin call cycle detected: ${cycle}`,
1474	      });
1475	    }
1476	    visiting.add(node);
1477	    for (const next of graph.get(node) ?? []) {
1478	      visit(next, [...stack, node]);
1479	    }
1480	    visiting.delete(node);
1481	    done.add(node);
1482	  };
1483	
1484	  for (const name of graph.keys()) visit(name, []);
1485	}
1486	
1487	function verifyCalls(plugins: Plugin[], bus: HookBus): void {
1488	  for (const p of plugins) {
1489	    for (const hook of p.manifest.calls) {
1490	      if (!bus.hasService(hook)) {
1491	        throw new PluginError({
1492	          code: 'missing-service',
1493	          plugin: p.manifest.name,
1494	          message: `plugin '${p.manifest.name}' declares calls:['${hook}'] but no plugin registers it`,
1495	        });
1496	      }
1497	    }
1498	  }
1499	}
