+import { describe, it, expect, beforeAll, afterEach } from 'vitest';
+import { spawnSync } from 'node:child_process';
+import { mkdtempSync, rmSync, existsSync } from 'node:fs';
+import { tmpdir } from 'node:os';
+import { join } from 'node:path';
+import BetterSqlite3 from 'better-sqlite3';
+
+const repoRoot = join(__dirname, '..', '..', '..', '..');
+const cliEntry = join(__dirname, '..', '..', 'dist', 'main.js');
+
+describe('@ax/cli end-to-end', () => {
+  let workDir: string;
+
+  beforeAll(() => {
+    // Ensure the CLI and its workspace deps are built. spawnSync with an
+    // argv array avoids shell quoting / injection — there is no user input
+    // here, but keeping shell: false is the repo's safer-by-default pattern.
+    const built = spawnSync(
+      'pnpm',
+      ['--filter', '@ax/cli...', 'build'],
+      { cwd: repoRoot, encoding: 'utf8', stdio: 'inherit' },
+    );
+    if (built.status !== 0) {
+      throw new Error(`workspace build failed (exit ${built.status})`);
+    }
+    if (!existsSync(cliEntry)) {
+      throw new Error(`CLI entry not found at ${cliEntry}; build must have failed`);
+    }
+  }, 120000);
+
+  afterEach(() => {
+    if (workDir && existsSync(workDir)) {
+      rmSync(workDir, { recursive: true, force: true });
+    }
+  });
+
+  it('runs a full chat and persists the outcome to SQLite', () => {
+    workDir = mkdtempSync(join(tmpdir(), 'ax-next-e2e-'));
+    const dbPath = join(workDir, 'e2e.sqlite');
+
+    const result = spawnSync('node', [cliEntry, 'hi'], {
+      env: { ...process.env, AX_DB: dbPath },
+      encoding: 'utf8',
+    });
+
+    expect(result.status).toBe(0);
+    expect(result.stdout.trim()).toBe('hello');
+
+    expect(existsSync(dbPath)).toBe(true);
+    const db = new BetterSqlite3(dbPath, { readonly: true });
+    try {
+      const rows = db
+        .prepare('SELECT key, value FROM kv')
+        .all() as Array<{ key: string; value: Buffer }>;
+      expect(rows.length).toBeGreaterThanOrEqual(1);
+      const chatRow = rows.find((r) => r.key.startsWith('chat:'));
+      expect(chatRow).toBeDefined();
+      const decoded = JSON.parse(chatRow!.value.toString('utf8'));
+      expect(decoded).toMatchObject({
+        sessionId: 'cli-session',
+        outcome: {
+          kind: 'complete',
+          messages: expect.arrayContaining([
+            { role: 'assistant', content: 'hello' },
+          ]),
+        },
+      });
+      expect(chatRow!.key).toMatch(/^chat:.+/);
+      expect(typeof decoded.timestamp).toBe('string');
+    } finally {
+      db.close();
+    }
+  });
+
+  it('non-zero exit when a plugin init fails', () => {
+    workDir = mkdtempSync(join(tmpdir(), 'ax-next-e2e-'));
+    // Pointing AX_DB at a directory (not a file) forces SQLite open to fail
+    // at init, which bubbles up as `init-failed` → non-zero CLI exit.
+    const result = spawnSync('node', [cliEntry, 'hi'], {
+      env: { ...process.env, AX_DB: workDir },
+      encoding: 'utf8',
+    });
+    expect(result.status).toBe(2);
+    expect(result.stderr).toMatch(/fatal:/);
+  });","path":"packages/cli/src/__tests__/e2e.test.ts","commit_id":"379f7215fd13d3e29e21660c3406cfd7137c8b57","original_commit_id":"1c1aa0636b85b24b04e939ab0cf47532523448f2","user":{"login":"vpulim","id":100092,"node_id":"MDQ6VXNlcjEwMDA5Mg==","avatar_url":"https://avatars.githubusercontent.com/u/100092?v=4","gravatar_id":"","url":"https://api.github.com/users/vpulim","html_url":"https://github.com/vpulim","followers_url":"https://api.github.com/users/vpulim/followers","following_url":"https://api.github.com/users/vpulim/following{/other_user}","gists_url":"https://api.github.com/users/vpulim/gists{/gist_id}","starred_url":"https://api.github.com/users/vpulim/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/vpulim/subscriptions","organizations_url":"https://api.github.com/users/vpulim/orgs","repos_url":"https://api.github.com/users/vpulim/repos","events_url":"https://api.github.com/users/vpulim/events{/privacy}","received_events_url":"https://api.github.com/users/vpulim/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"Pushing back on the cross-platform concern here. The test already asserts `stderr` matches `/fatal:/` (added in commit 524f323), so it does check error content, not just exit code.

Specifically what exit code 2 pins: it's the CLI's outer IIFE `.catch()` path that writes `fatal: ${e.message}` and exits 2. That's the CLI error-handling contract, not better-sqlite3's behavior. If better-sqlite3 ever stopped throwing on AX_DB=directory and started silently creating a file, the test would correctly fail (exit would be 0), which is the behavior we want.

On platform support: CI is Linux, dev is Linux + macOS. Both behave consistently here. Windows is not a supported target for ax-next — it would break in plenty of other places first (the pathToFileURL fix being an exception because it's cheap and the plan anticipated it). Adding chmod-0 scaffolding for a platform we don't ship on would be YAGNI.

Happy to revisit if/when Windows enters scope.","created_at":"2026-04-23T18:40:06Z","updated_at":"2026-04-23T18:40:06Z","html_url":"https://github.com/project-ax/ax-next/pull/2#discussion_r3133007814","pull_request_url":"https://api.github.com/repos/project-ax/ax-next/pulls/2","_links":{"self":{"href":"https://api.github.com/repos/project-ax/ax-next/pulls/comments/3133007814"},"html":{"href":"https://github.com/project-ax/ax-next/pull/2#discussion_r3133007814"},"pull_request":{"href":"https://api.github.com/repos/project-ax/ax-next/pulls/2"}},"reactions":{"url":"https://api.github.com/repos/project-ax/ax-next/pulls/comments/3133007814/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":75,"original_start_line":75,"start_side":"RIGHT","line":85,"original_line":85,"side":"RIGHT","in_reply_to_id":3132592210,"author_association":"MEMBER","original_position":85,"position":85,"subject_type":"line"}

